interface.signature:
interface DrillProps {
  difficulty: 'easy' | 'medium' | 'hard';
  sessionId: string;
  onComplete: (result: DrillResult) => void;
  onSkip?: () => void;  // Optional skip functionality (deferred to Epic 4)
}

interface DrillResult {
  id: string;                     // UUID
  sessionId: string;              // Foreign key to sessions.id
  timestamp: string;              // ISO 8601 drill completion time
  module: 'number_line';
  difficulty: 'easy' | 'medium' | 'hard';
  isCorrect: boolean;
  timeToAnswer: number;           // Milliseconds
  accuracy: number;               // Percentage (0-100)

  // Number Line specific fields
  targetNumber: number;           // e.g., 47
  userAnswer: number;             // User's placement (calculated from marker position)
  correctAnswer: number;          // Same as targetNumber for validation
}

db.drill_results.add({
  id: crypto.randomUUID(),
  sessionId: string,
  timestamp: new Date().toISOString(),
  module: 'number_line',
  // ... other DrillResult fields
})
